function renderTool(e){const t=document.createElement("div");t.className="tool-wrap",t.innerHTML=`\n    <div class="tool-header">\n      <button class="btn-back" onclick="App.closePanel()">\n        <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M19 12H5M12 5l-7 7 7 7"/></svg>\n        Kembali\n      </button>\n      <div class="tool-meta">\n        <span class="tool-badge badge-${e.outputType}">${badgeLabel(e.outputType)}</span>\n        <h2 class="tool-title">${e.name}</h2>\n        <p class="tool-desc">${e.description}</p>\n      </div>\n    </div>\n    <div class="tool-body">\n      <div class="form-section" id="form-${e.id}"></div>\n      <button class="btn-generate" id="btn-${e.id}">\n        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"/></svg>\n        Generate\n      </button>\n      <div class="output-section" id="out-${e.id}"></div>\n    </div>`;const n=t.querySelector(`#form-${e.id}`);return e.inputs.forEach(e=>{const t=document.createElement("div");t.className="form-group",t.innerHTML=`<label class="form-label">${e.label}${e.required?'<span class="required">*</span>':""}</label>${buildInput(e)}`,n.appendChild(t)}),t.querySelector(`#btn-${e.id}`).onclick=()=>doGenerate(e,t),t}function buildInput(e){const t=`i_${e.id}`;switch(e.type){case"text":return`<input type="text" class="form-input" id="${t}" placeholder="${e.label}" ${e.required?"required":""}>`;case"textarea":return`<textarea class="form-textarea" id="${t}" rows="3" placeholder="${e.label}"></textarea>`;case"select":return`<select class="form-select" id="${t}">${(e.options||[]).map(e=>`<option value="${e}">${e}</option>`).join("")}</select>`;case"file":return`\n        <div class="form-upload" onclick="document.getElementById('${t}').click()">\n          <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" y1="3" x2="12" y2="15"/></svg>\n          <span>Klik untuk upload</span>\n          <input type="file" id="${t}" accept="${e.accept||"image/*"}" style="display:none" onchange="handlePreview(this,'prev_${e.id}')">\n        </div>\n        <div id="prev_${e.id}" class="form-preview"></div>`;case"range":return`\n        <div class="form-range-wrap">\n          <input type="range" class="form-range" id="${t}" min="${e.min||1}" max="${e.max||5}" value="${e.default||1}"\n            oninput="document.getElementById('val_${e.id}').textContent=this.value">\n          <div class="range-display">\n            <span class="range-label">${e.min||1}</span>\n            <span class="range-value" id="val_${e.id}">${e.default||1}</span>\n            <span class="range-label">${e.max||5}</span>\n          </div>\n        </div>`;case"number":return`<input type="number" class="form-input" id="${t}" min="${e.min||1}" max="${e.max||100}" value="${e.default||""}">`;default:return`<input type="text" class="form-input" id="${t}" placeholder="${e.label}">`}}function handlePreview(e,t){const n=document.getElementById(t);n&&e.files[0]&&(e.files[0].type.startsWith("image/")?n.innerHTML=`<img src="${URL.createObjectURL(e.files[0])}" class="preview-img">`:n.innerHTML=`<div class="preview-file">📎 ${e.files[0].name}</div>`)}function getValues(e){const t={};return e.inputs.forEach(e=>{const n=document.getElementById(`i_${e.id}`);n&&(t[e.id]="file"===e.type?n.files[0]||null:n.value||"")}),t}function buildPrompt(e,t){return e.promptTemplate.replace(/\{\{([\w-]+)\}\}/g,(e,n)=>{const i=t[n];return!i||i instanceof File?"":i})}function badgeLabel(e){return{text:"📝 Text",image:"🖼️ Image",image_text:"🖼️+📝 Text+Image",sound:"🔊 Audio"}[e]||e}async function doGenerate(e,t){const n=t.querySelector(`#btn-${e.id}`),i=t.querySelector(`#out-${e.id}`),a=e.inputs.filter(e=>e.required&&"file"!==e.type&&!document.getElementById(`i_${e.id}`)?.value).map(e=>e.label);if(a.length)showError(i,`Wajib diisi: ${a.join(", ")}`);else{n.disabled=!0,n.innerHTML='<span class="spinner"></span> Generating...',showLoading(i);try{const t=getValues(e),n=buildPrompt(e,t),a=e.inputs.filter(e=>"file"===e.type).map(e=>t[e.id]).find(e=>e instanceof File);if("text"===e.outputType||"sound"===e.outputType)showText(i,await aiText(n));else if("image"===e.outputType)if(a){showImages(i,await aiImageFromRef(n,a))}else{const e=parseInt(t.jumlah||"1");showImages(i,await aiImage(n,e))}else if("image_text"===e.outputType)if(a){const[e,t]=await Promise.all([aiText(n),aiImageFromRef(n,a)]);i.innerHTML="",showText(i,e,!1),showImages(i,t,!0)}else{const e=parseInt(t.jumlah||"1"),[a,o]=await Promise.all([aiText(n),aiImage(n,e)]);i.innerHTML="",showText(i,a,!1),showImages(i,o,!0)}}catch(e){showError(i,e.message)}finally{n.disabled=!1,n.innerHTML='<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"/></svg> Generate'}}}function showLoading(e){e.innerHTML='<div class="output-loading">\n    <div class="loading-dots"><span></span><span></span><span></span></div>\n    <p>AI sedang memproses...</p>\n  </div>'}function showError(e,t){e.innerHTML=`<div class="output-error">\n    <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>\n    ${t}\n  </div>`}function showText(e,t,n=!1){n||(e.innerHTML="");const i=document.createElement("div");i.className="output-box output-appear",i.innerHTML=`\n    <div class="output-toolbar">\n      <span class="output-label">\n        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/></svg>\n        Hasil\n      </span>\n      <button class="btn-copy" onclick="copyText(this,\`${esc(t)}\`)">\n        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1"/></svg>\n        Copy\n      </button>\n    </div>\n    <div class="output-text">${mdToHtml(t)}</div>`,e.appendChild(i)}function showImages(e,t,n=!1){n||(e.innerHTML="");const i=document.createElement("div");i.className="output-box output-appear";const a=t.map((e,t)=>`\n    <div class="img-card">\n      <img src="${e}" alt="Hasil ${t+1}" onclick="openImgFull('${e}')">\n      <button class="btn-dl" onclick="dlImg('${e}','hasil-${t+1}.png')">\n        <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21 15v4a2 2 0 01-2 2H5a2 2 0 01-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>\n        Download\n      </button>\n    </div>`).join("");i.innerHTML=`\n    <div class="output-toolbar">\n      <span class="output-label">\n        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg>\n        ${t.length} Gambar\n      </span>\n    </div>\n    <div class="img-grid">${a}</div>`,e.appendChild(i)}function copyText(e,t){const n=t.replace(/&#39;/g,"'").replace(/&quot;/g,'"').replace(/&lt;/g,"<").replace(/&gt;/g,">").replace(/&amp;/g,"&").replace(/&#96;/g,"`");navigator.clipboard.writeText(n).then(()=>{e.innerHTML='<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="20 6 9 17 4 12"/></svg> Tersalin!',e.classList.add("copied"),setTimeout(()=>{e.innerHTML='<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="9" y="9" width="13" height="13" rx="2"/><path d="M5 15H4a2 2 0 01-2-2V4a2 2 0 012-2h9a2 2 0 012 2v1"/></svg> Copy',e.classList.remove("copied")},2e3)})}function dlImg(e,t){const n=document.createElement("a");n.href=e,n.download=t,n.click()}function openImgFull(e){window.open("","_blank").document.write(`<html><body style="margin:0;background:#000;display:flex;align-items:center;justify-content:center;min-height:100vh"><img src="${e}" style="max-width:100%;max-height:100vh;object-fit:contain"></body></html>`)}function mdToHtml(e){return e.replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/\*\*(.*?)\*\*/g,"<strong>$1</strong>").replace(/\*(.*?)\*/g,"<em>$1</em>").replace(/^### (.+)$/gm,"<h4>$1</h4>").replace(/^## (.+)$/gm,"<h3>$1</h3>").replace(/^# (.+)$/gm,"<h2>$1</h2>").replace(/^[-•] (.+)$/gm,"<li>$1</li>").replace(/(<li>[\s\S]*?<\/li>)/g,"<ul>$1</ul>").replace(/\n\n/g,"</p><p>").replace(/\n/g,"<br>")}function esc(e){return String(e).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;").replace(/`/g,"&#96;")}